import { useState, useRef, useEffect } from "react";
import { createClient } from "@supabase/supabase-js";

const LOGO_B64 = "";

// ─── DESIGN TOKENS ─────────────────────────────────────────────────────────────
// Brand: preto #0D0D0D, branco #FFFFFF, gradiente iB: amarelo→laranja→pink
// #FFB800 → #FF6B00 → #FF2D78

const CSS = `
  @import url('https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@400;600;700;800;900&family=Barlow:wght@300;400;500;600;700&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --bg: #F5F5F7;
    --bg2: #EBEBED;
    --surface: #FFFFFF;
    --surface2: #F0F0F2;
    --border: rgba(0,0,0,0.08);
    --border2: rgba(0,0,0,0.05);

    /* Brand gradients from logo */
    --ib-yellow: #FFB800;
    --ib-orange: #FF6B00;
    --ib-pink: #FF2D78;
    --ib-grad: linear-gradient(135deg, #FFB800 0%, #FF6B00 50%, #FF2D78 100%);
    --ib-grad-glow: rgba(255,107,0,0.2);

    --black: #0D0D0D;
    --black2: #1A1A1A;
    --black3: #2D2D2D;
    --text: #0D0D0D;
    --text2: #5A5A5A;
    --text3: #9A9A9A;

    --green: #00C853;
    --red: #FF3B30;
    --blue: #0071E3;

    --gold: #FFD700;
    --silver: #8E8E93;
    --bronze: #CD7F32;

    --r: 18px;
    --r2: 12px;
    --shadow: 0 2px 16px rgba(0,0,0,0.08);
    --shadow-md: 0 8px 32px rgba(0,0,0,0.12);
  }

  html, body { height: 100%; background: var(--bg); color: var(--text); font-family: 'Barlow', sans-serif; }
  #root { height: 100%; }

  .app { display: flex; flex-direction: column; height: 100%; max-width: 430px; margin: 0 auto; background: var(--bg); position: relative; overflow: hidden; }
  .page { flex: 1; overflow-y: auto; padding-bottom: 88px; scrollbar-width: none; }
  .page::-webkit-scrollbar { display: none; }

  /* BOTTOM NAV */
  .nav { position: fixed; bottom: 0; left: 50%; transform: translateX(-50%); width: 100%; max-width: 430px; background: rgba(255,255,255,0.95); backdrop-filter: blur(20px); border-top: 1px solid var(--border); display: flex; z-index: 100; padding: 8px 0 20px; }
  .nav-item { flex: 1; display: flex; flex-direction: column; align-items: center; gap: 3px; cursor: pointer; color: var(--text3); transition: color 0.2s; font-size: 10px; font-weight: 600; letter-spacing: 0.2px; }
  .nav-item.active { color: var(--ib-orange); }
  .nav-item svg { width: 22px; height: 22px; }
  .nav-add-wrap { flex: 1; display: flex; justify-content: center; }
  .nav-add { width: 52px; height: 52px; border-radius: 50%; background: var(--ib-grad); display: flex; align-items: center; justify-content: center; margin-top: -20px; box-shadow: 0 4px 20px var(--ib-grad-glow); cursor: pointer; transition: transform 0.2s; }
  .nav-add:active { transform: scale(0.92); }

  /* HEADER */
  .header { padding: 16px 20px 8px; display: flex; align-items: center; justify-content: space-between; }
  .header-logo { height: 28px; width: auto; object-fit: contain; }
  .header-title { font-family: 'Barlow Condensed', sans-serif; font-size: 22px; font-weight: 800; color: var(--black); text-transform: uppercase; letter-spacing: 0.5px; }

  /* CARDS */
  .card { background: var(--surface); border-radius: var(--r); padding: 16px; box-shadow: var(--shadow); }
  .card-dark { background: var(--black); color: white; }
  .card-grad { background: var(--ib-grad); color: white; }

  /* HERO SCORE CARD */
  .score-hero { background: var(--black); border-radius: 24px; padding: 24px; position: relative; overflow: hidden; }
  .score-hero::before { content: ''; position: absolute; top: -40px; right: -40px; width: 160px; height: 160px; background: var(--ib-grad); opacity: 0.15; border-radius: 50%; }
  .score-hero::after { content: ''; position: absolute; bottom: -30px; left: -20px; width: 100px; height: 100px; background: linear-gradient(135deg, #FFB800, #FF6B00); opacity: 0.1; border-radius: 50%; }

  /* SCORE NUM */
  .score-num { font-family: 'Barlow Condensed', sans-serif; letter-spacing: -1px; font-weight: 900; }
  .score-grad { background: var(--ib-grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
  .label { font-size: 10px; font-weight: 700; color: var(--text3); text-transform: uppercase; letter-spacing: 0.8px; }
  .title { font-size: 20px; font-weight: 700; }
  .subtitle { font-size: 13px; color: var(--text2); }

  /* PROGRESS BAR */
  .progress-wrap { background: var(--bg2); border-radius: 99px; overflow: hidden; }
  .progress-fill { height: 100%; border-radius: 99px; background: var(--ib-grad); transition: width 0.8s cubic-bezier(.34,1.56,.64,1); }

  /* AVATAR */
  .avatar { border-radius: 50%; display: flex; align-items: center; justify-content: center; font-weight: 700; flex-shrink: 0; }

  /* BUTTONS */
  .btn { border: none; border-radius: 12px; font-family: 'Barlow', sans-serif; font-weight: 700; cursor: pointer; transition: all 0.15s; display: flex; align-items: center; justify-content: center; gap: 8px; }
  .btn:active { transform: scale(0.96); }
  .btn-primary { background: var(--black); color: white; padding: 14px 24px; font-size: 15px; width: 100%; }
  .btn-grad { background: var(--ib-grad); color: white; padding: 14px 24px; font-size: 15px; width: 100%; box-shadow: 0 4px 16px var(--ib-grad-glow); }
  .btn-outline { background: transparent; color: var(--black); padding: 10px 18px; font-size: 13px; border: 2px solid var(--black); border-radius: 10px; }
  .btn-ghost { background: var(--surface2); color: var(--text); padding: 8px 14px; font-size: 13px; border-radius: 10px; }
  .btn-danger { background: rgba(255,59,48,0.08); color: var(--red); border: 1px solid rgba(255,59,48,0.15); padding: 6px 12px; font-size: 12px; border-radius: 8px; }

  /* INPUT */
  .input { background: var(--surface2); border: 1.5px solid var(--border); border-radius: 12px; padding: 13px 14px; color: var(--text); font-family: 'Barlow', sans-serif; font-size: 14px; font-weight: 500; width: 100%; outline: none; transition: border-color 0.2s; }
  .input:focus { border-color: var(--ib-orange); background: white; }
  .input::placeholder { color: var(--text3); }
  select.input { cursor: pointer; }

  /* CHIP */
  .chip { display: inline-flex; align-items: center; gap: 4px; padding: 4px 10px; border-radius: 99px; font-size: 11px; font-weight: 700; }
  .chip-orange { background: rgba(255,107,0,0.12); color: var(--ib-orange); }
  .chip-green { background: rgba(0,200,83,0.12); color: var(--green); }
  .chip-red { background: rgba(255,59,48,0.1); color: var(--red); }
  .chip-blue { background: rgba(0,113,227,0.1); color: var(--blue); }
  .chip-black { background: var(--black); color: white; }
  .chip-grad { background: var(--ib-grad); color: white; }

  /* SECTION */
  .section { padding: 0 16px 12px; }
  .section-title { font-size: 13px; font-weight: 700; color: var(--text2); text-transform: uppercase; letter-spacing: 0.8px; margin-bottom: 10px; }

  /* POINT TYPE GRID */
  .point-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 10px; }
  .point-btn { background: var(--surface); border: 2px solid var(--border); border-radius: 16px; padding: 16px 12px; cursor: pointer; transition: all 0.15s; display: flex; flex-direction: column; align-items: center; gap: 6px; box-shadow: var(--shadow); }
  .point-btn:active { transform: scale(0.95); }
  .point-btn.selected { border-color: var(--ib-orange); background: rgba(255,107,0,0.04); box-shadow: 0 0 0 3px rgba(255,107,0,0.12); }
  .point-btn-icon { font-size: 26px; }
  .point-btn-name { font-size: 12px; font-weight: 700; text-align: center; color: var(--text); line-height: 1.3; }
  .point-btn-pts { font-family: 'Barlow Condensed', sans-serif; font-size: 20px; font-weight: 800; background: var(--ib-grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }

  /* RANKING */
  .rank-item { display: flex; align-items: center; gap: 12px; padding: 12px 16px; border-radius: 16px; margin-bottom: 6px; background: var(--surface); box-shadow: var(--shadow); transition: all 0.2s; }
  .rank-item.me { background: var(--black); }
  .rank-item.me .rank-name { color: white; }
  .rank-item.me .rank-pts { color: rgba(255,255,255,0.6); }
  .rank-num { font-family: 'Barlow Condensed', sans-serif; font-size: 22px; font-weight: 800; width: 28px; text-align: center; flex-shrink: 0; color: var(--text3); }
  .rank-info { flex: 1; }
  .rank-name { font-size: 15px; font-weight: 700; }
  .rank-pts { font-size: 12px; color: var(--text2); margin-top: 1px; }
  .rank-score { font-family: 'Barlow Condensed', sans-serif; font-size: 26px; font-weight: 900; background: var(--ib-grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
  .rank-item.me .rank-score { background: white; -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }

  /* HISTORY */
  .history-item { display: flex; align-items: center; gap: 12px; padding: 12px 0; border-bottom: 1px solid var(--border2); }
  .history-icon { width: 38px; height: 38px; border-radius: 12px; background: var(--bg2); display: flex; align-items: center; justify-content: center; font-size: 18px; flex-shrink: 0; }
  .history-info { flex: 1; }
  .history-action { font-size: 13px; font-weight: 600; }
  .history-meta { font-size: 11px; color: var(--text3); margin-top: 2px; }
  .history-pts { font-family: 'Barlow Condensed', sans-serif; font-size: 22px; font-weight: 800; background: var(--ib-grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }

  /* ACHIEVEMENT */
  .ach-item { display: flex; align-items: center; gap: 12px; padding: 12px; background: var(--surface); border-radius: 14px; margin-bottom: 8px; box-shadow: var(--shadow); }
  .ach-item.locked { opacity: 0.35; filter: grayscale(1); }
  .ach-icon { font-size: 28px; width: 46px; height: 46px; display: flex; align-items: center; justify-content: center; background: var(--bg2); border-radius: 14px; flex-shrink: 0; }
  .ach-info { flex: 1; }
  .ach-name { font-size: 13px; font-weight: 700; }
  .ach-desc { font-size: 11px; color: var(--text2); margin-top: 2px; }
  .ach-unlocked { width: 22px; height: 22px; background: var(--ib-grad); border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 11px; flex-shrink: 0; }

  /* TOAST */
  .toast { position: fixed; top: 20px; left: 50%; transform: translateX(-50%) translateY(-120px); background: var(--black); border-radius: 18px; padding: 14px 20px; display: flex; align-items: center; gap: 12px; z-index: 999; transition: transform 0.4s cubic-bezier(.34,1.56,.64,1); max-width: 340px; width: 90%; box-shadow: 0 8px 32px rgba(0,0,0,0.25); }
  .toast.show { transform: translateX(-50%) translateY(0); }
  .toast-icon { font-size: 26px; }
  .toast-text { font-size: 15px; font-weight: 700; color: white; }
  .toast-sub { font-size: 12px; color: rgba(255,255,255,0.6); margin-top: 2px; }

  /* CONFETTI */
  .confetti-container { position: fixed; top: 0; left: 0; width: 100%; height: 100%; pointer-events: none; z-index: 998; overflow: hidden; }
  @keyframes confettiFall { 0% { transform: translateY(-10px) rotate(0deg); opacity: 1; } 100% { transform: translateY(100vh) rotate(720deg); opacity: 0; } }
  .confetti-piece { position: absolute; border-radius: 2px; animation: confettiFall linear forwards; }

  /* MINI CHART */
  .chart-bar-wrap { display: flex; align-items: flex-end; gap: 4px; height: 60px; }
  .chart-bar { flex: 1; border-radius: 4px 4px 0 0; background: var(--ib-grad); min-height: 4px; }
  .chart-label { font-size: 9px; font-weight: 600; color: var(--text3); text-align: center; margin-top: 4px; text-transform: uppercase; }

  /* PROGRESS */
  .progress-wrap { background: var(--bg2); border-radius: 99px; overflow: hidden; }
  .progress-fill { border-radius: 99px; background: var(--ib-grad); transition: width 0.8s cubic-bezier(.34,1.56,.64,1); }

  /* TABS */
  .tabs { display: flex; background: var(--bg2); border-radius: 12px; padding: 3px; margin-bottom: 16px; }
  .tab { flex: 1; padding: 8px; text-align: center; font-size: 13px; font-weight: 700; border-radius: 10px; cursor: pointer; color: var(--text3); transition: all 0.2s; }
  .tab.active { background: var(--black); color: white; }

  /* MODAL */
  .modal-bg { position: fixed; inset: 0; background: rgba(0,0,0,0.5); backdrop-filter: blur(4px); z-index: 200; display: flex; align-items: flex-end; justify-content: center; }
  .modal { background: white; border-top-left-radius: 28px; border-top-right-radius: 28px; padding: 24px; width: 100%; max-width: 430px; max-height: 90vh; overflow-y: auto; animation: slideUp 0.3s cubic-bezier(.34,1.56,.64,1); }
  @keyframes slideUp { from { transform: translateY(100%); } to { transform: translateY(0); } }
  .modal-handle { width: 36px; height: 4px; background: var(--bg2); border-radius: 99px; margin: 0 auto 20px; }

  /* STAT GRID */
  .stat-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
  .stat-card { background: var(--surface); border-radius: 16px; padding: 14px; box-shadow: var(--shadow); }
  .stat-val { font-family: 'Barlow Condensed', sans-serif; font-size: 30px; font-weight: 900; color: var(--black); }
  .stat-lbl { font-size: 11px; font-weight: 600; color: var(--text3); margin-top: 2px; text-transform: uppercase; letter-spacing: 0.4px; }

  /* HSCROLL */
  .hscroll { display: flex; gap: 10px; overflow-x: auto; padding-bottom: 4px; scrollbar-width: none; }
  .hscroll::-webkit-scrollbar { display: none; }

  /* CAMPAIGN CARD */
  .campaign-card { border-radius: 18px; padding: 18px; margin-bottom: 12px; }
  .campaign-active { background: var(--black); }
  .campaign-future { background: var(--surface); box-shadow: var(--shadow); }
  .campaign-finished { background: var(--surface2); }

  /* LOGIN */
  .login-bg { min-height: 100vh; display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 24px; background: var(--bg); }
  .login-card { background: white; border-radius: 24px; padding: 32px 24px; width: 100%; max-width: 360px; box-shadow: var(--shadow-md); }
  .login-logo { display: block; width: 100px; height: 100px; object-fit: contain; margin: 0 auto 8px; }
  .login-brand { font-family: 'Barlow Condensed', sans-serif; font-size: 28px; font-weight: 900; text-align: center; color: var(--black); letter-spacing: 1px; margin-bottom: 4px; text-transform: uppercase; }
  .login-tagline { font-size: 12px; font-weight: 600; color: var(--text3); text-align: center; margin-bottom: 28px; text-transform: uppercase; letter-spacing: 0.8px; }

  /* EMPTY */
  .empty { text-align: center; padding: 40px 20px; color: var(--text3); }
  .empty-icon { font-size: 40px; margin-bottom: 12px; }

  /* UTILS */
  .flex { display: flex; }
  .flex-col { flex-direction: column; }
  .items-center { align-items: center; }
  .justify-between { justify-content: space-between; }
  .gap-2 { gap: 8px; }
  .gap-3 { gap: 12px; }
  .mt-2 { margin-top: 8px; }
  .mt-3 { margin-top: 12px; }
  .mt-4 { margin-top: 16px; }
  .mb-2 { margin-bottom: 8px; }
  .mb-3 { margin-bottom: 12px; }
  .mb-4 { margin-bottom: 16px; }
  .fw-700 { font-weight: 700; }
  .text-sm { font-size: 13px; }
  .text-xs { font-size: 11px; }
  .text-white { color: white; }
  .text-muted { color: var(--text2); }
  .text-grad { background: var(--ib-grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
  .w-full { width: 100%; }

  /* BADGE RANK */
  .rank-badge-1 { background: linear-gradient(135deg, #FFD700, #FFA500); color: #000; width: 28px; height: 28px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 14px; flex-shrink: 0; }
  .rank-badge-2 { background: linear-gradient(135deg, #C0C0C0, #8E8E93); color: #000; width: 28px; height: 28px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 14px; flex-shrink: 0; }
  .rank-badge-3 { background: linear-gradient(135deg, #CD7F32, #A0522D); color: #000; width: 28px; height: 28px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 14px; flex-shrink: 0; }

  @keyframes pulse-grad { 0%,100% { box-shadow: 0 4px 16px rgba(255,107,0,0.3); } 50% { box-shadow: 0 4px 28px rgba(255,107,0,0.6); } }
  .pulse-btn { animation: pulse-grad 2s infinite; }

  /* ── RANKING SCREEN ── */
  .rk-camp { padding: 0 16px 12px; }
  .rk-camp-name { font-family: 'Barlow Condensed', sans-serif; font-size: 26px; font-weight: 900; color: var(--black); text-transform: uppercase; letter-spacing: 0.3px; line-height: 1; }
  .rk-camp-period { font-size: 12px; font-weight: 600; color: var(--text3); margin-top: 4px; }

  /* period segmented control */
  .rk-seg { display: flex; gap: 6px; overflow-x: auto; padding: 0 16px 12px; scrollbar-width: none; }
  .rk-seg::-webkit-scrollbar { display: none; }
  .rk-seg-btn { flex-shrink: 0; padding: 8px 16px; border-radius: 99px; font-size: 13px; font-weight: 700; cursor: pointer; background: var(--surface); color: var(--text2); box-shadow: var(--shadow); transition: all 0.2s; border: none; white-space: nowrap; }
  .rk-seg-btn.active { background: var(--black); color: white; }

  /* type filter chips */
  .rk-types { display: flex; gap: 6px; overflow-x: auto; padding: 0 16px 14px; scrollbar-width: none; }
  .rk-types::-webkit-scrollbar { display: none; }
  .rk-type-chip { flex-shrink: 0; display: inline-flex; align-items: center; gap: 5px; padding: 6px 12px; border-radius: 99px; font-size: 12px; font-weight: 600; cursor: pointer; background: var(--surface2); color: var(--text2); border: 1.5px solid transparent; transition: all 0.15s; white-space: nowrap; }
  .rk-type-chip.active { border-color: var(--ib-orange); background: rgba(255,107,0,0.06); color: var(--ib-orange); }

  /* podium */
  .podium { display: flex; align-items: flex-end; justify-content: center; gap: 8px; padding: 8px 4px 4px; }
  .podium-col { flex: 1; display: flex; flex-direction: column; align-items: center; }
  .podium-av { position: relative; }
  .podium-medal { position: absolute; bottom: -6px; left: 50%; transform: translateX(-50%); font-size: 18px; }
  .podium-name { font-size: 12px; font-weight: 700; color: white; margin-top: 10px; line-height: 1.1; text-align: center; }
  .podium-pts { font-family: 'Barlow Condensed', sans-serif; font-weight: 900; line-height: 1; }
  .podium-base { width: 100%; border-radius: 10px 10px 0 0; margin-top: 8px; display: flex; align-items: flex-start; justify-content: center; padding-top: 6px; font-family: 'Barlow Condensed', sans-serif; font-weight: 900; color: rgba(255,255,255,0.25); font-size: 20px; }
  .pb-1 { height: 46px; background: linear-gradient(180deg, rgba(255,215,0,0.35), rgba(255,215,0,0.05)); }
  .pb-2 { height: 34px; background: linear-gradient(180deg, rgba(192,192,192,0.3), rgba(192,192,192,0.05)); }
  .pb-3 { height: 26px; background: linear-gradient(180deg, rgba(205,127,50,0.3), rgba(205,127,50,0.05)); }

  /* movement indicators */
  .mv { display: inline-flex; align-items: center; gap: 2px; font-size: 11px; font-weight: 800; }
  .mv-up { color: var(--green); }
  .mv-down { color: var(--red); }
  .mv-same { color: var(--text3); }

  /* my-summary sticky card */
  .my-summary { position: sticky; bottom: 0; margin: 8px 16px 0; }
  .my-card { background: var(--ib-grad); border-radius: 18px; padding: 16px; box-shadow: 0 6px 24px rgba(255,107,0,0.3); }
  .my-msg { background: rgba(0,0,0,0.18); border-radius: 12px; padding: 10px 12px; font-size: 13px; font-weight: 600; color: white; line-height: 1.4; }

  /* row enhancements */
  .rk-row { display: flex; align-items: center; gap: 12px; padding: 12px 14px; border-radius: 16px; margin-bottom: 6px; background: var(--surface); box-shadow: var(--shadow); transition: all 0.2s; }
  .rk-row.me { background: var(--black); }
  .rk-row.me .rk-name { color: white; }
  .rk-row.me .rk-sub { color: rgba(255,255,255,0.55); }
  .rk-pos { font-family: 'Barlow Condensed', sans-serif; font-size: 20px; font-weight: 800; width: 24px; text-align: center; flex-shrink: 0; color: var(--text3); }
  .rk-name { font-size: 15px; font-weight: 700; }
  .rk-sub { font-size: 11px; color: var(--text2); margin-top: 1px; display: flex; align-items: center; gap: 6px; }
  .rk-score-v { font-family: 'Barlow Condensed', sans-serif; font-size: 26px; font-weight: 900; background: var(--ib-grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
  .rk-row.me .rk-score-v { background: white; -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }

  @keyframes slideRise { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
  .rk-row { animation: slideRise 0.3s ease backwards; }

  /* ── LOADING / SYNC ── */
  .loading-bg { min-height: 100vh; display: flex; flex-direction: column; align-items: center; justify-content: center; background: var(--bg); gap: 20px; }
  .loading-logo { width: 88px; height: 88px; object-fit: contain; animation: logoPulse 1.4s ease-in-out infinite; }
  @keyframes logoPulse { 0%,100% { transform: scale(1); opacity: 1; } 50% { transform: scale(0.92); opacity: 0.6; } }
  .spinner { width: 28px; height: 28px; border: 3px solid var(--bg2); border-top-color: var(--ib-orange); border-radius: 50%; animation: spin 0.8s linear infinite; }
  @keyframes spin { to { transform: rotate(360deg); } }
  .sync-dot { position: fixed; top: 14px; right: 14px; z-index: 300; display: flex; align-items: center; gap: 6px; background: rgba(0,0,0,0.75); color: white; font-size: 10px; font-weight: 700; padding: 5px 10px; border-radius: 99px; opacity: 0; transition: opacity 0.3s; pointer-events: none; }
  .sync-dot.show { opacity: 1; }
  .sync-spin { width: 10px; height: 10px; border: 2px solid rgba(255,255,255,0.3); border-top-color: white; border-radius: 50%; animation: spin 0.7s linear infinite; }

  /* empty-state seed prompt */
  .seed-box { margin: 0 16px; padding: 24px; text-align: center; background: var(--surface); border-radius: 18px; box-shadow: var(--shadow); }
`;

