// ─── RANKING ───────────────────────────────────────────────────────────────────
function MovementBadge({ prevRank, currentRank }) {
  if (prevRank === undefined || prevRank === Infinity) return <span className="mv mv-same">–</span>;
  const diff = prevRank - currentRank; // positive = moved up
  if (diff > 0) return <span className="mv mv-up">▲ {diff}</span>;
  if (diff < 0) return <span className="mv mv-down">▼ {Math.abs(diff)}</span>;
  return <span className="mv mv-same">–</span>;
}

function Ranking({ user, sellers, entries, campaigns, snapshots }) {
  const [period, setPeriod] = useState("campaign");
  const [type, setType] = useState("all");
  const activeCampaign = campaigns.find(c => c.status === "active");
  const isSeller = user.role !== "admin";

  const filtered = filterEntries(entries, { period, type, campaignId: activeCampaign?.id });
  const ranking = buildRanking(sellers, filtered);
  const movement = movementFromSnapshots(snapshots, dayKey());

  const me = ranking.find(r => r.id === user.id);
  const above = me ? ranking[me.rank - 2] : null;
  const ptsToNext = above ? above.total - me.total : 0;
  const third = ranking[2];
  const ptsToTop3 = me && me.rank > 3 && third ? (third.total - me.total + 1) : 0;
  const myPrev = me ? movement[me.id] : undefined;

  // Motivational message for the logged seller
  function myMessage() {
    if (!me) return null;
    const didTodayCount = filterEntries(entries, { period: "today", type: "all", campaignId: activeCampaign?.id }).some(e => e.sellerId === me.id);
    if (me.rank === 1) return "👑 Você está liderando. Mantenha o ritmo!";
    if (me.rank <= 3) return "🔥 Você está no pódio. Segure essa posição!";
    if (ptsToTop3 > 0 && ptsToTop3 <= 15) return `🏅 Faltam só ${ptsToTop3} pontos para entrar no Top 3!`;
    if (myPrev !== undefined && myPrev < me.rank) return "💪 Você caiu de posição, mas ainda dá pra recuperar essa semana.";
    if (!didTodayCount) return "⚡ Faça uma ação hoje para movimentar seu ranking!";
    return "🚀 Continue pontuando para subir no ranking!";
  }

  const periods = [["today","Hoje"],["week","Semana"],["month","Mês"],["campaign","Campanha"]];

  return (
    <div className="page">
      <div className="header">
        <div className="header-title">🏆 Ranking</div>
      </div>

      {/* Campaign header */}
      <div className="rk-camp">
        <div className="rk-camp-name">{activeCampaign?.name || "Sem campanha ativa"}</div>
        {activeCampaign && (
          <div className="rk-camp-period">
            📅 {new Date(activeCampaign.start).toLocaleDateString("pt-BR")} — {new Date(activeCampaign.end).toLocaleDateString("pt-BR")}
          </div>
        )}
      </div>

      {/* Period segmented */}
      <div className="rk-seg">
        {periods.map(([v,l]) => (
          <button key={v} className={`rk-seg-btn ${period===v?"active":""}`} onClick={()=>setPeriod(v)}>{l}</button>
        ))}
      </div>

      {/* Type filter chips */}
      <div className="rk-types">
        <div className={`rk-type-chip ${type==="all"?"active":""}`} onClick={()=>setType("all")}>🏆 Tudo</div>
        {POINT_TYPES.map(pt => (
          <div key={pt.id} className={`rk-type-chip ${type===pt.id?"active":""}`} onClick={()=>setType(pt.id)}>
            {pt.icon} {pt.name.replace("Venda ","").replace("Avaliação ","")}
          </div>
        ))}
      </div>

      {/* Podium */}
      {ranking.length >= 1 && (
        <div className="section">
          <div className="score-hero">
            <div className="label" style={{color:"rgba(255,255,255,0.4)",marginBottom:6}}>Pódio {type!=="all" && `· ${POINT_TYPES.find(p=>p.id===type)?.name}`}</div>
            <div className="podium">
              {/* 2nd */}
              {ranking[1] ? (
                <div className="podium-col">
                  <div className="podium-av"><Avatar seller={ranking[1]} size={44} /><span className="podium-medal">🥈</span></div>
                  <div className="podium-name">{ranking[1].name.split(" ")[0]}</div>
                  <div className="podium-pts score-grad" style={{fontSize:22}}>{ranking[1].total}</div>
                  <div className="podium-base pb-2">2</div>
                </div>
              ) : <div className="podium-col" />}
              {/* 1st */}
              <div className="podium-col">
                <div style={{fontSize:20,marginBottom:2}}>👑</div>
                <div className="podium-av"><Avatar seller={ranking[0]} size={58} /><span className="podium-medal" style={{fontSize:22}}>🥇</span></div>
                <div className="podium-name" style={{fontSize:13}}>{ranking[0].name.split(" ")[0]}</div>
                <div className="podium-pts score-grad" style={{fontSize:30}}>{ranking[0].total}</div>
                <div className="podium-base pb-1">1</div>
              </div>
              {/* 3rd */}
              {ranking[2] ? (
                <div className="podium-col">
                  <div className="podium-av"><Avatar seller={ranking[2]} size={40} /><span className="podium-medal">🥉</span></div>
                  <div className="podium-name">{ranking[2].name.split(" ")[0]}</div>
                  <div className="podium-pts score-grad" style={{fontSize:20}}>{ranking[2].total}</div>
                  <div className="podium-base pb-3">3</div>
                </div>
              ) : <div className="podium-col" />}
            </div>
          </div>
        </div>
      )}

      {/* Full list */}
      <div className="section">
        <div className="section-title">Classificação Geral</div>
        {ranking.map((s, idx) => (
          <div key={s.id} className={`rk-row ${s.id===user.id?"me":""}`} style={{animationDelay:`${idx*40}ms`}}>
            <div className="rk-pos">{s.rank}</div>
            <Avatar seller={s} size={40} />
            <div style={{flex:1}}>
              <div className="rk-name">
                {s.name} {s.id===user.id && <span className="chip chip-orange" style={{fontSize:9,padding:"2px 6px"}}>você</span>}
              </div>
              <div className="rk-sub">
                <span>{s.total} pts</span>
                <span>·</span>
                <MovementBadge prevRank={movement[s.id]} currentRank={s.rank} />
                {s.organic > 0 && <span style={{color:"var(--text3)"}}>· 🤝 {s.organic}</span>}
              </div>
            </div>
            <div className="rk-score-v">{s.total}</div>
          </div>
        ))}
      </div>

    </div>
  );
}


// ─── LAUNCH POINTS ─────────────────────────────────────────────────────────────
function LaunchPoints({ user, sellers, entries, setEntries, campaigns, showToast, showConfetti }) {
  const [selSeller, setSelSeller] = useState("");
  const [selType, setSelType] = useState(null);
  const [note, setNote] = useState("");
  const [loading, setLoading] = useState(false);
  const activeCampaign = campaigns.find(c=>c.status==="active");

  function confirm() {
    if (!selSeller||!selType) return;
    setLoading(true);
    const pt = POINT_TYPES.find(p=>p.id===selType);
    const seller = sellers.find(s=>s.id===selSeller);
    setTimeout(()=>{
      const entry = { id:uid("e"), sellerId:selSeller, campaignId:activeCampaign?.id||null, type:selType, pts:pt.pts, note, date:new Date().toISOString(), addedBy:user.id };
      setEntries(prev=>[...prev,entry]);
      showToast({title:`+${pt.pts} pts para ${seller.name.split(" ")[0]}`, sub:`por ${pt.name}`});
      showConfetti();
      setSelSeller(""); setSelType(null); setNote(""); setLoading(false);
    },600);
  }

  return (
    <div className="page">
      <div className="header"><div className="header-title">⚡ Lançar Pontos</div></div>
      <div className="section">
        {sellers.filter(s=>s.active).length === 0 ? (
          <div className="seed-box">
            <div style={{fontSize:36,marginBottom:8}}>👥</div>
            <div className="fw-700" style={{fontSize:15,marginBottom:4}}>Nenhum vendedor cadastrado</div>
            <div className="text-sm text-muted">Cadastre vendedores na aba Equipe antes de lançar pontos.</div>
          </div>
        ) : (<>
        <div className="label mb-2">Vendedor</div>
        <select className="input mb-4" value={selSeller} onChange={e=>setSelSeller(e.target.value)}>
          <option value="">Selecione o vendedor...</option>
          {sellers.filter(s=>s.active).map(s=><option key={s.id} value={s.id}>{s.avatar} {s.name}</option>)}
        </select>

        <div className="label mb-2">Tipo de Ponto</div>
        <div className="point-grid mb-4">
          {POINT_TYPES.map(pt=>(
            <div key={pt.id} className={`point-btn ${selType===pt.id?"selected":""}`} onClick={()=>setSelType(pt.id)}>
              <div className="point-btn-icon">{pt.icon}</div>
              <div className="point-btn-name">{pt.name}</div>
              <div className="point-btn-pts">+{pt.pts} pts</div>
            </div>
          ))}
        </div>

        <div className="label mb-2">Observação (opcional)</div>
        <input className="input mb-4" placeholder="Ex: venda no Instagram..." value={note} onChange={e=>setNote(e.target.value)} />

        {selSeller && selType && (
          <div className="card mb-3" style={{borderLeft:"4px solid var(--ib-orange)"}}>
            <div className="text-sm fw-700">Confirmar lançamento</div>
            <div className="text-sm text-muted mt-2">
              {sellers.find(s=>s.id===selSeller)?.name} → {POINT_TYPES.find(p=>p.id===selType)?.name} (+{POINT_TYPES.find(p=>p.id===selType)?.pts} pts)
            </div>
          </div>
        )}

        <button className={`btn btn-grad ${(!selSeller||!selType)?"":"pulse-btn"}`} onClick={confirm} disabled={!selSeller||!selType||loading} style={{opacity:(!selSeller||!selType)?0.4:1}}>
          {loading ? "Lançando..." : "✅ Confirmar Pontos"}
        </button>
        </>)}
      </div>
    </div>
  );
}

// ─── PROFILE ───────────────────────────────────────────────────────────────────
function Profile({ user, sellers, entries, setEntries, isAdmin }) {
  const [viewSeller, setViewSeller] = useState(user.role==="admin" ? null : user.id);
  const ranking = getRanking(sellers, entries, null);

  if (user.role==="admin" && !viewSeller) {
    return (
      <div className="page">
        <div className="header"><div className="header-title">👥 Vendedores</div></div>
        <div className="section">
          {ranking.map(s=>(
            <div key={s.id} className="rank-item" onClick={()=>setViewSeller(s.id)} style={{cursor:"pointer"}}>
              <RankBadge rank={s.rank} />
              <Avatar seller={s} size={42} />
              <div className="rank-info"><div className="rank-name">{s.name}</div><div className="rank-pts">{s.total} pts</div></div>
              <div style={{fontSize:16,color:"var(--text3)"}}>›</div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  const seller = sellers.find(s=>s.id===viewSeller)||user;
  const rank = ranking.find(r=>r.id===viewSeller)||{rank:"-",total:0};
  const myEntries = entries.filter(e=>e.sellerId===viewSeller).reverse();
  const chart = getChartData(entries, viewSeller);
  const achievements = checkAchievements(entries, viewSeller);
  const avgPts = sellers.length>0 ? Math.round(entries.reduce((a,e)=>a+e.pts,0)/sellers.filter(s=>s.active).length) : 0;

  return (
    <div className="page">
      <div className="header">
        {user.role==="admin" && <button className="btn btn-ghost" style={{fontSize:13}} onClick={()=>setViewSeller(null)}>← Voltar</button>}
        <div className="header-title" style={{flex:1,textAlign:user.role==="admin"?"right":"left"}}>{user.role!=="admin"?"Meu Perfil":seller.name}</div>
      </div>

      <div className="section">
        <div className="score-hero" style={{textAlign:"center"}}>
          <div style={{marginBottom:10,display:"flex",justifyContent:"center"}}>
            {seller.photo
              ? <div style={{width:72,height:72,borderRadius:"50%",overflow:"hidden",border:"3px solid rgba(255,255,255,0.3)"}}><img src={seller.photo} style={{width:"100%",height:"100%",objectFit:"cover"}} /></div>
              : <div style={{fontSize:56}}>{seller.avatar||"🧑"}</div>}
          </div>
          <div style={{fontSize:20,fontWeight:800,color:"white"}}>{seller.name}</div>
          <div style={{fontSize:12,color:"rgba(255,255,255,0.5)",marginBottom:16}}>Vendedor · iPhone Barato</div>
          <div className="score-num score-grad" style={{fontSize:64,lineHeight:1}}>{rank.total}</div>
          <div style={{fontSize:13,color:"rgba(255,255,255,0.6)"}}>pontos totais</div>
          <div style={{marginTop:10}}><span className="chip chip-grad">#{rank.rank} no ranking</span></div>
        </div>
      </div>

      <div className="section">
        <div className="stat-grid">
          <div className="stat-card"><div className="stat-val">{weekPts(entries,viewSeller)}</div><div className="stat-lbl">pts semana</div></div>
          <div className="stat-card"><div className="stat-val">{monthPts(entries,viewSeller)}</div><div className="stat-lbl">pts mês</div></div>
          <div className="stat-card"><div className="stat-val">{myEntries.length}</div><div className="stat-lbl">lançamentos</div></div>
          <div className="stat-card"><div className="stat-val" style={{fontSize:24}}>{POINT_TYPES.sort((a,b)=>{const c=buildStats(entries,viewSeller); return (c[b.id]*b.pts)-(c[a.id]*a.pts);})[0]?.icon}</div><div className="stat-lbl">melhor cat.</div></div>
        </div>
      </div>

      <div className="section">
        <div className="card">
          <div className="section-title">vs. Média da Equipe</div>
          <div className="flex justify-between mb-2">
            <div className="text-sm fw-700">{seller.name.split(" ")[0]}: <span className="text-grad">{rank.total} pts</span></div>
            <div className="text-sm text-muted">Média: {avgPts} pts</div>
          </div>
          <ProgressBar value={rank.total} max={Math.max(rank.total, avgPts, 1)} height={8} />
        </div>
      </div>

      <div className="section">
        <div className="card"><div className="section-title">Evolução — 7 dias</div><MiniChart data={chart} /></div>
      </div>

      <div className="section">
        <div className="section-title">Conquistas</div>
        {achievements.map(a=>(
          <div key={a.id} className={`ach-item ${a.unlocked?"":"locked"}`}>
            <div className="ach-icon">{a.icon}</div>
            <div className="ach-info"><div className="ach-name">{a.name}</div><div className="ach-desc">{a.desc}</div></div>
            {a.unlocked && <div className="ach-unlocked">✓</div>}
          </div>
        ))}
      </div>

      <div className="section">
        <div className="section-title">Histórico</div>
        <div className="card">
          {myEntries.length===0 && <div className="empty"><div className="empty-icon">📭</div><div>Sem lançamentos</div></div>}
          {myEntries.map(e=>{
            const pt = POINT_TYPES.find(p=>p.id===e.type);
            return (
              <div key={e.id} className="history-item">
                <div className="history-icon">{pt?.icon}</div>
                <div className="history-info"><div className="history-action">{pt?.name}</div><div className="history-meta">{fmtDate(e.date)}{e.note&&` · ${e.note}`}</div></div>
                <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:4}}>
                  <div className="history-pts">+{e.pts}</div>
                  {isAdmin && <button className="btn btn-danger" onClick={()=>setEntries(prev=>prev.filter(x=>x.id!==e.id))}>✕</button>}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// ─── VENDORS ───────────────────────────────────────────────────────────────────
function VendorManagement({ sellers, setSellers }) {
  const [showForm, setShowForm] = useState(false);
  const [editPhotoId, setEditPhotoId] = useState(null);
  const [form, setForm] = useState({name:"",password:"",avatar:"🧑",photo:""});
  const photoInputRef = useRef(null);
  const editPhotoInputRef = useRef(null);

  function saveSeller() {
    if (!form.name||!form.password) return;
    setSellers(prev=>[...prev,{id:uid("s"),name:form.name,avatar:form.avatar,photo:form.photo,active:true,role:"seller",password:form.password}]);
    setForm({name:"",password:"",avatar:"🧑",photo:""}); setShowForm(false);
  }

  function handlePhotoFile(file, cb) {
    if (!file) return;
    compressPhoto(file, cb);
  }

  return (
    <div className="page">
      <div className="header">
        <div className="header-title">👥 Equipe</div>
        <button className="btn btn-outline" style={{fontSize:12}} onClick={()=>setShowForm(true)}>+ Novo</button>
      </div>
      <div className="section">
        {sellers.map(s=>(
          <div key={s.id} className="rank-item">
            <div style={{position:"relative",cursor:"pointer"}} onClick={()=>{setEditPhotoId(s.id);setTimeout(()=>editPhotoInputRef.current?.click(),50);}}>
              <Avatar seller={s} size={42} />
              <div style={{position:"absolute",bottom:-2,right:-2,width:16,height:16,borderRadius:"50%",background:"var(--ib-orange)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,color:"white",fontWeight:700,boxShadow:"0 1px 4px rgba(0,0,0,0.3)"}}>📷</div>
            </div>
            <div className="rank-info">
              <div className="rank-name">{s.name}</div>
              <div style={{fontSize:11,fontWeight:600,color:s.active?"var(--green)":"var(--red)",marginTop:2}}>{s.active?"● Ativo":"● Inativo"}</div>
            </div>
            <button className={`btn ${s.active?"btn-danger":"btn-ghost"}`} style={{fontSize:11}} onClick={()=>setSellers(prev=>prev.map(x=>x.id===s.id?{...x,active:!x.active}:x))}>
              {s.active?"Inativar":"Ativar"}
            </button>
          </div>
        ))}
      </div>

      {/* hidden input for editing existing seller photo */}
      <input ref={editPhotoInputRef} type="file" accept="image/*" style={{display:"none"}} onChange={e=>{
        const file = e.target.files?.[0];
        if (!file || !editPhotoId) return;
        handlePhotoFile(file, photo => {
          setSellers(prev=>prev.map(s=>s.id===editPhotoId?{...s,photo}:s));
          setEditPhotoId(null);
        });
        e.target.value="";
      }} />

      {showForm && (
        <div className="modal-bg" onClick={e=>e.target===e.currentTarget&&(setShowForm(false),setForm({name:"",password:"",avatar:"🧑",photo:""}))}>
          <div className="modal">
            <div className="modal-handle" />
            <div className="title mb-3">Novo Vendedor</div>

            {/* Photo upload */}
            <div className="label mb-2">Foto</div>
            <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:16}}>
              <div style={{width:64,height:64,borderRadius:"50%",overflow:"hidden",background:"var(--bg2)",border:"2px solid var(--border)",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                {form.photo
                  ? <img src={form.photo} style={{width:"100%",height:"100%",objectFit:"cover"}} />
                  : <span style={{fontSize:28}}>{form.avatar}</span>}
              </div>
              <div style={{flex:1}}>
                <button className="btn btn-outline" style={{fontSize:12,width:"100%",marginBottom:6}} onClick={()=>photoInputRef.current?.click()}>
                  📷 {form.photo ? "Trocar foto" : "Adicionar foto"}
                </button>
                {form.photo && <button className="btn btn-ghost" style={{fontSize:11,width:"100%",color:"var(--red)"}} onClick={()=>setForm(f=>({...f,photo:""}))}>Remover foto</button>}
              </div>
              <input ref={photoInputRef} type="file" accept="image/*" style={{display:"none"}} onChange={e=>{
                const file=e.target.files?.[0];
                if (file) handlePhotoFile(file, photo=>setForm(f=>({...f,photo})));
                e.target.value="";
              }} />
            </div>

            {/* Emoji (used as fallback when no photo) */}
            {!form.photo && <>
              <div className="label mb-2">Emoji (opcional)</div>
              <div style={{display:"flex",flexWrap:"wrap",gap:8,marginBottom:16}}>
                {AVATARS.map(av=>(
                  <div key={av} onClick={()=>setForm(f=>({...f,avatar:av}))} style={{width:42,height:42,borderRadius:12,background:form.avatar===av?"rgba(255,107,0,0.12)":"var(--bg2)",border:form.avatar===av?"2px solid var(--ib-orange)":"2px solid transparent",display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,cursor:"pointer"}}>
                    {av}
                  </div>
                ))}
              </div>
            </>}

            <div className="label mb-2">Nome Completo</div>
            <input className="input mb-3" placeholder="Nome do vendedor" value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} />
            <div className="label mb-2">Senha</div>
            <input className="input mb-4" type="password" placeholder="Senha de acesso" value={form.password} onChange={e=>setForm(f=>({...f,password:e.target.value}))} />
            <button className="btn btn-grad" onClick={saveSeller}>Cadastrar Vendedor</button>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── CAMPAIGNS ─────────────────────────────────────────────────────────────────
function Campaigns({ campaigns, setCampaigns, sellers, entries }) {
  const EMPTY = {id:null,name:"",start:"",end:"",prizes:[""],status:""};
  const [form, setForm] = useState(EMPTY);
  const [showForm, setShowForm] = useState(false);
  const [confirmDel, setConfirmDel] = useState(false);

  function autoStatus(start, end) {
    const now=new Date(), s=new Date(start), e=new Date(end);
    if (now>=s && now<=e) return "active";
    if (now>e) return "finished";
    return "future";
  }

  function openCreate() {
    setForm({...EMPTY, prizes:["","",""]});
    setConfirmDel(false);
    setShowForm(true);
  }

  function openEdit(c) {
    setForm({id:c.id, name:c.name, start:c.start, end:c.end, prizes:c.prizes.length?[...c.prizes]:[""], status:c.status});
    setConfirmDel(false);
    setShowForm(true);
  }

  function closeForm() { setShowForm(false); setConfirmDel(false); }

  function saveForm() {
    if (!form.name||!form.start||!form.end) return;
    const prizes = form.prizes.filter(Boolean);
    const status = form.status || autoStatus(form.start, form.end);
    if (form.id) {
      setCampaigns(prev=>prev.map(c=>c.id===form.id?{...c,name:form.name,start:form.start,end:form.end,prizes,status}:c));
    } else {
      setCampaigns(prev=>[...prev,{id:uid("c"),name:form.name,start:form.start,end:form.end,status,prizes,rules:POINT_TYPES}]);
    }
    closeForm();
  }

  function deleteCampaign() {
    setCampaigns(prev=>prev.filter(c=>c.id!==form.id));
    closeForm();
  }

  const MEDALS = ["🥇","🥈","🥉"];

  return (
    <div className="page">
      <div className="header">
        <div className="header-title">🏁 Campanhas</div>
        <button className="btn btn-outline" style={{fontSize:12}} onClick={openCreate}>+ Nova</button>
      </div>
      <div className="section">
        {campaigns.map(c=>{
          const campEntries = entries.filter(e=>e.campaignId===c.id);
          const ranking = getRanking(sellers, campEntries, c.id);
          const isActive = c.status==="active";
          return (
            <div key={c.id} className={`campaign-card campaign-${c.status}`}>
              <div className="flex justify-between items-center mb-2">
                <div style={{fontSize:16,fontWeight:800,color:isActive?"white":"var(--black)",flex:1,marginRight:8}}>{c.name}</div>
                <div style={{display:"flex",gap:6,alignItems:"center",flexShrink:0}}>
                  <span className={`chip ${isActive?"chip-green":"chip-orange"}`}>{isActive?"🔥 Ativa":c.status==="future"?"⏳ Futura":"✅ Encerrada"}</span>
                  <button className="btn btn-ghost" style={{fontSize:11,padding:"4px 10px",color:isActive?"rgba(255,255,255,0.7)":"var(--text2)",minWidth:0}} onClick={()=>openEdit(c)}>✏️</button>
                </div>
              </div>
              <div style={{fontSize:11,fontWeight:600,color:isActive?"rgba(255,255,255,0.5)":"var(--text3)",marginBottom:12}}>
                {new Date(c.start).toLocaleDateString("pt-BR")} → {new Date(c.end).toLocaleDateString("pt-BR")}
              </div>
              {c.prizes?.length>0 && (
                <div className="mb-3">
                  {c.prizes.map((p,i)=>(
                    <div key={i} style={{fontSize:13,fontWeight:600,color:isActive?"rgba(255,255,255,0.8)":"var(--text2)",marginBottom:3}}>
                      {MEDALS[i]||"🏅"} {p}
                    </div>
                  ))}
                </div>
              )}
              {ranking.length>0 && (
                <div>
                  <div style={{fontSize:10,fontWeight:700,color:isActive?"rgba(255,255,255,0.4)":"var(--text3)",textTransform:"uppercase",letterSpacing:"0.6px",marginBottom:8}}>Top 3 Atual</div>
                  {ranking.slice(0,3).map((s,i)=>(
                    <div key={s.id} className="flex items-center gap-2 mb-1">
                      <span style={{fontSize:14}}>{MEDALS[i]}</span>
                      <span style={{fontSize:13,fontWeight:600,color:isActive?"white":"var(--text)",flex:1}}>{s.name}</span>
                      <span style={{fontFamily:"Barlow Condensed, sans-serif",fontSize:16,fontWeight:800,background:"var(--ib-grad)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent"}}>{s.total} pts</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {showForm && (
        <div className="modal-bg" onClick={e=>e.target===e.currentTarget&&closeForm()}>
          <div className="modal">
            <div className="modal-handle" />
            <div className="title mb-3">{form.id?"Editar Campanha":"Nova Campanha"}</div>

            <div className="label mb-2">Nome</div>
            <input className="input mb-3" placeholder="Ex: Campanha Julho" value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} />

            <div className="flex gap-2 mb-3">
              <div style={{flex:1}}><div className="label mb-2">Início</div><input className="input" type="date" value={form.start} onChange={e=>setForm(f=>({...f,start:e.target.value}))} /></div>
              <div style={{flex:1}}><div className="label mb-2">Fim</div><input className="input" type="date" value={form.end} onChange={e=>setForm(f=>({...f,end:e.target.value}))} /></div>
            </div>

            <div className="label mb-2">Status</div>
            <div style={{display:"flex",gap:8,marginBottom:16}}>
              {[["future","⏳ Futura"],["active","🔥 Ativa"],["finished","✅ Encerrada"]].map(([v,l])=>(
                <button key={v} className={`btn ${form.status===v?"btn-grad":"btn-outline"}`} style={{flex:1,fontSize:11,padding:"8px 2px"}} onClick={()=>setForm(f=>({...f,status:v}))}>
                  {l}
                </button>
              ))}
            </div>

            <div className="label mb-2">Premiação</div>
            {form.prizes.map((p,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
                <span style={{fontSize:18,width:24,textAlign:"center",flexShrink:0}}>{MEDALS[i]||"🏅"}</span>
                <input className="input" placeholder={`${i+1}º Prêmio...`} value={p} onChange={e=>setForm(f=>{const pz=[...f.prizes];pz[i]=e.target.value;return{...f,prizes:pz};})} style={{flex:1}} />
                {form.prizes.length>1 && (
                  <button className="btn btn-ghost" style={{padding:"0 10px",fontSize:18,color:"var(--red)",flexShrink:0}} onClick={()=>setForm(f=>({...f,prizes:f.prizes.filter((_,idx)=>idx!==i)}))}>×</button>
                )}
              </div>
            ))}
            <button className="btn btn-ghost" style={{fontSize:12,width:"100%",marginBottom:16}} onClick={()=>setForm(f=>({...f,prizes:[...f.prizes,""]}))}>+ Adicionar prêmio</button>

            <button className="btn btn-grad" style={{marginBottom:8}} onClick={saveForm}>{form.id?"Salvar Alterações":"Criar Campanha"}</button>

            {form.id && !confirmDel && (
              <button className="btn btn-ghost" style={{width:"100%",color:"var(--red)",fontSize:12}} onClick={()=>setConfirmDel(true)}>Excluir campanha</button>
            )}
            {form.id && confirmDel && (
              <div style={{background:"rgba(255,45,72,0.08)",borderRadius:12,padding:12,textAlign:"center",marginTop:4}}>
                <div style={{fontSize:13,fontWeight:600,color:"var(--red)",marginBottom:10}}>Excluir permanentemente?</div>
                <div style={{display:"flex",gap:8}}>
                  <button className="btn btn-ghost" style={{flex:1,fontSize:12}} onClick={()=>setConfirmDel(false)}>Cancelar</button>
                  <button className="btn btn-danger" style={{flex:1,fontSize:12}} onClick={deleteCampaign}>Excluir</button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// ─── ICONS ──────────────────────────────────────────────────────────────────────
function Icon({ name }) {
  const icons = {
    home: <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>,
    trophy: <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="8 21 12 17 16 21"/><line x1="12" y1="17" x2="12" y2="11"/><path d="M7 4h10l1 7H6z"/><path d="M5 11a4 4 0 0 0 4 4h6a4 4 0 0 0 4-4"/></svg>,
    plus: <svg viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2.5" strokeLinecap="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>,
    user: <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>,
    flag: <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M4 15s1-1 4-1 5 2 8 2 4-1 4-1V3s-1 1-4 1-5-2-8-2-4 1-4 1z"/><line x1="4" y1="22" x2="4" y2="15"/></svg>,
    users: <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>,
    logout: <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>,
  };
  return icons[name]||null;
}

// ─── APP ROOT ───────────────────────────────────────────────────────────────────
export default function App() {
  const [user, setUser] = useState(null);
  const [tab, setTab] = useState("home");
  const [sellers, setSellers] = useState([]);
  const [entries, setEntries] = useState([]);
  const [campaigns, setCampaigns] = useState([]);
  const [snapshots, setSnapshots] = useState({});
  const [loading, setLoading] = useState(true);
  const [syncing, setSyncing] = useState(false);
  const [toast, setToast] = useState(null);
  const [showToastFlag, setShowToastFlag] = useState(false);
  const [confetti, setConfetti] = useState(false);
  const toastRef = useRef(null);
  const loadedRef = useRef(false);
  const syncTimer = useRef(null);

  // ── Load everything from the shared backend on first mount ──
  useEffect(() => {
    let alive = true;
    (async () => {
      const data = await api.loadAll();
      if (!alive) return;
      setSellers(data.sellers || []);
      setCampaigns(data.campaigns || []);
      setEntries(data.entries || []);
      setSnapshots(data.snapshots || {});
      loadedRef.current = true;
      setLoading(false);
      // Restore remembered session
      try {
        const saved = localStorage.getItem("ib_session");
        if (saved) {
          const { userId } = JSON.parse(saved);
          if (userId === "admin") {
            setUser({ id:"admin", name:"Gestor", role:"admin" });
          } else {
            const seller = (data.sellers || []).find(s => s.id === userId && s.active);
            if (seller) setUser(seller);
            else localStorage.removeItem("ib_session");
          }
        }
      } catch { localStorage.removeItem("ib_session"); }
    })();
    return () => { alive = false; };
  }, []);

  // ── Persist whenever a collection changes (after initial load) ──
  function flashSync() {
    setSyncing(true);
    clearTimeout(syncTimer.current);
    syncTimer.current = setTimeout(() => setSyncing(false), 700);
  }
  useEffect(() => { if (loadedRef.current) { api.save(DB_KEYS.sellers, sellers); flashSync(); } }, [sellers]);
  useEffect(() => { if (loadedRef.current) { api.save(DB_KEYS.campaigns, campaigns); flashSync(); } }, [campaigns]);
  useEffect(() => { if (loadedRef.current) { api.save(DB_KEYS.entries, entries); flashSync(); } }, [entries]);
  useEffect(() => { if (loadedRef.current) { api.save(DB_KEYS.snapshots, snapshots); } }, [snapshots]);

  // ── Record a daily rank snapshot (once per day, on data change) ──
  useEffect(() => {
    if (!loadedRef.current || sellers.length === 0) return;
    const activeCampaign = campaigns.find(c => c.status === "active");
    const today = dayKey();
    const ranking = buildRanking(sellers, filterEntries(entries, { period: "campaign", type: "all", campaignId: activeCampaign?.id }));
    const todayMap = {};
    ranking.forEach(s => { todayMap[s.id] = s.rank; });
    setSnapshots(prev => {
      const existing = prev[today];
      // skip write if unchanged to avoid loops
      if (existing && JSON.stringify(existing) === JSON.stringify(todayMap)) return prev;
      return { ...prev, [today]: todayMap };
    });
  }, [entries, sellers, campaigns]);

  function triggerToast(msg) { setToast(msg); setShowToastFlag(true); clearTimeout(toastRef.current); toastRef.current = setTimeout(()=>setShowToastFlag(false), 3200); }
  function triggerConfetti() { setConfetti(true); setTimeout(()=>setConfetti(false), 2500); }

  // Seed a starter campaign so admin isn't fully blocked (data starts empty otherwise)
  function seedStarterCampaign() {
    const now = new Date();
    const end = new Date(now.getFullYear(), now.getMonth() + 1, 0);
    setCampaigns([{ id: uid("c"), name: `Campanha ${now.toLocaleDateString("pt-BR",{month:"long"})}`, start: dayKey(now), end: dayKey(end), status: "active", prizes: ["", "", ""], rules: POINT_TYPES }]);
  }

  const isAdmin = user?.role==="admin";

  const adminTabs = [
    {id:"home",label:"Início",icon:"home"},
    {id:"ranking",label:"Ranking",icon:"trophy"},
    {id:"launch",label:"",icon:"plus"},
    {id:"vendors",label:"Equipe",icon:"users"},
    {id:"campaigns",label:"Camp.",icon:"flag"},
  ];
  const sellerTabs = [
    {id:"home",label:"Início",icon:"home"},
    {id:"ranking",label:"Ranking",icon:"trophy"},
    {id:"profile",label:"Perfil",icon:"user"},
    {id:"campaigns",label:"Camp.",icon:"flag"},
  ];
  const tabs = isAdmin ? adminTabs : sellerTabs;

  // ── Loading screen while backend data loads ──
  if (loading) return (
    <>
      <style>{CSS}</style>
      <div className="loading-bg">
        <img src={`data:image/jpeg;base64,${LOGO_B64}`} className="loading-logo" alt="iPhone Barato" />
        <div className="spinner" />
        <div style={{fontSize:13,fontWeight:600,color:"var(--text3)"}}>Carregando dados...</div>
      </div>
    </>
  );

  function handleLogin(u, remember) {
    setUser(u);
    setTab("home");
    if (remember) localStorage.setItem("ib_session", JSON.stringify({ userId: u.id }));
    else localStorage.removeItem("ib_session");
  }
  function handleLogout() {
    localStorage.removeItem("ib_session");
    setUser(null);
  }

  if (!user) return (<><style>{CSS}</style><LoginScreen sellers={sellers} onLogin={handleLogin} /></>);

  function renderPage() {
    switch(tab) {
      case "home":
        if (isAdmin) {
          const activeCampaign = campaigns.find(c=>c.status==="active");
          const ranking = getRanking(sellers, entries, activeCampaign?.id);
          return (
            <div className="page">
              <div className="header">
                <img src={`data:image/jpeg;base64,${LOGO_B64}`} className="header-logo" alt="Logo" />
                <button className="btn btn-ghost" style={{fontSize:12}} onClick={handleLogout}>Sair</button>
              </div>
              <div className="section">
                <div className="score-hero mb-3">
                  <div className="label" style={{color:"rgba(255,255,255,0.4)",marginBottom:8}}>Painel do Gestor 👑</div>
                  <div className="stat-grid">
                    {[
                      [sellers.filter(s=>s.active).length,"vendedores"],
                      [entries.length,"lançamentos"],
                      [entries.reduce((a,e)=>a+e.pts,0),"pontos"],
                      [campaigns.filter(c=>c.status==="active").length,"campanhas ativas"],
                    ].map(([v,l],i)=>(
                      <div key={i} style={{background:"rgba(255,255,255,0.07)",borderRadius:12,padding:"12px 14px"}}>
                        <div className="score-num score-grad" style={{fontSize:28}}>{v}</div>
                        <div style={{fontSize:10,fontWeight:700,color:"rgba(255,255,255,0.4)",textTransform:"uppercase",letterSpacing:"0.4px",marginTop:2}}>{l}</div>
                      </div>
                    ))}
                  </div>
                </div>
                <div className="section-title">Top 3 — Campanha Atual</div>
                {ranking.length === 0 && (
                  <div className="seed-box mb-3">
                    <div style={{fontSize:36,marginBottom:8}}>🚀</div>
                    <div className="fw-700" style={{fontSize:15,marginBottom:4}}>Comece por aqui</div>
                    <div className="text-sm text-muted mb-3">
                      {campaigns.length === 0
                        ? "Crie sua primeira campanha e cadastre os vendedores para começar a pontuar."
                        : "Cadastre os vendedores na aba Equipe para começar a lançar pontos."}
                    </div>
                    {campaigns.length === 0 && <button className="btn btn-grad mb-2" onClick={seedStarterCampaign}>+ Criar campanha do mês</button>}
                    <button className="btn btn-outline w-full" onClick={()=>setTab(campaigns.length===0?"campaigns":"vendors")}>
                      {campaigns.length === 0 ? "Ir para Campanhas" : "Ir para Equipe"}
                    </button>
                  </div>
                )}
                {ranking.slice(0,3).map((s,i)=>(
                  <div key={s.id} className="rank-item">
                    <RankBadge rank={i+1} />
                    <Avatar seller={s} size={42} />
                    <div className="rank-info"><div className="rank-name">{s.name}</div><div className="rank-pts">{s.total} pontos</div></div>
                    <div className="rank-score">{s.total}</div>
                  </div>
                ))}
                <div className="section-title mt-3">Últimos Lançamentos</div>
                <div className="card">
                  {[...entries].reverse().slice(0,8).map(e=>{
                    const pt=POINT_TYPES.find(p=>p.id===e.type); const sel=sellers.find(s=>s.id===e.sellerId);
                    return (
                      <div key={e.id} className="history-item">
                        <div className="history-icon">{pt?.icon}</div>
                        <div className="history-info"><div className="history-action">{sel?.name} · {pt?.name}</div><div className="history-meta">{fmtDate(e.date)}</div></div>
                        <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:4}}>
                          <div className="history-pts">+{e.pts}</div>
                          <button className="btn btn-danger" onClick={()=>setEntries(prev=>prev.filter(x=>x.id!==e.id))}>✕</button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          );
        }
        return <Dashboard user={user} sellers={sellers} entries={entries} campaigns={campaigns} />;
      case "ranking": return <Ranking user={user} sellers={sellers} entries={entries} campaigns={campaigns} snapshots={snapshots} />;
      case "launch": return <LaunchPoints user={user} sellers={sellers} entries={entries} setEntries={setEntries} campaigns={campaigns} showToast={triggerToast} showConfetti={triggerConfetti} />;
      case "profile": return <Profile user={user} sellers={sellers} entries={entries} setEntries={setEntries} isAdmin={isAdmin} />;
      case "vendors": return <VendorManagement sellers={sellers} setSellers={setSellers} />;
      case "campaigns": return <Campaigns campaigns={campaigns} setCampaigns={setCampaigns} sellers={sellers} entries={entries} />;
      default: return null;
    }
  }

  return (
    <>
      <style>{CSS}</style>
      <Confetti show={confetti} />
      <Toast msg={toast} show={showToastFlag} />
      <div className={`sync-dot ${syncing?"show":""}`}><div className="sync-spin" /> salvando</div>
      <div className="app">
        {renderPage()}
        <nav className="nav">
          {tabs.map((t)=>{
            if (t.icon==="plus" && isAdmin) {
              return (
                <div key={t.id} className="nav-add-wrap">
                  <div className="nav-add" onClick={()=>setTab("launch")}><Icon name="plus" /></div>
                </div>
              );
            }
            return (
              <div key={t.id} className={`nav-item ${tab===t.id?"active":""}`} onClick={()=>setTab(t.id)}>
                <Icon name={t.icon} />
                <span>{t.label}</span>
              </div>
            );
          })}
          {!isAdmin && (
            <div className="nav-item" onClick={handleLogout}>
              <Icon name="logout" /><span>Sair</span>
            </div>
          )}
        </nav>
      </div>
    </>
  );
}
